import os
import torch
import numpy as np
from torch import nn, optim
from torch.utils.data import Dataset, DataLoader, random_split
import matplotlib.pyplot as plt

# Setup working directory
working_dir = os.path.join(os.getcwd(), "working")
os.makedirs(working_dir, exist_ok=True)

# Device configuration
device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
print(f"Using device: {device}")


# Define synthetic dataset
class CosmologyDataset(Dataset):
    def __init__(self, size=1000):
        self.data = np.random.uniform(0, 2, (size, 1))
        self.targets = np.sin(self.data) + 0.1 * np.random.randn(size, 1)

    def __len__(self):
        return len(self.data)

    def __getitem__(self, index):
        return torch.FloatTensor(self.data[index]), torch.FloatTensor(
            self.targets[index]
        )


dataset = CosmologyDataset()
train_size = int(0.8 * len(dataset))
val_size = len(dataset) - train_size
train_dataset, val_dataset = random_split(dataset, [train_size, val_size])
train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)
val_loader = DataLoader(val_dataset, batch_size=32)

experiment_data = {
    "output_layer_variation": {
        "synthetic_cosmology": {
            "metrics": {"train": [], "val": []},
            "losses": {"train": [], "val": []},
            "predictions": [],
            "ground_truth": [],
            "variation_types": [],
        },
    }
}


def create_model(output_variation):
    class SimpleModel(nn.Module):
        def __init__(self):
            super(SimpleModel, self).__init__()
            self.base = nn.Sequential(
                nn.Linear(1, 64),
                nn.ReLU(),
                nn.Linear(64, 64),
                nn.ReLU(),
            )
            if output_variation == "relu":
                self.output = nn.Sequential(nn.Linear(64, 1), nn.ReLU())
            elif output_variation == "extra_layer":
                self.output = nn.Sequential(
                    nn.Linear(64, 32), nn.ReLU(), nn.Linear(32, 1)
                )
            else:
                self.output = nn.Linear(64, 1)

        def forward(self, x):
            x = self.base(x)
            return self.output(x)

    return SimpleModel().to(device)


output_variations = ["linear", "relu", "extra_layer"]
for variation in output_variations:
    model = create_model(variation)
    criterion = nn.MSELoss()
    optimizer = optim.Adam(model.parameters(), lr=0.001)

    num_epochs = 20
    for epoch in range(num_epochs):
        model.train()
        training_loss = 0.0
        for batch in train_loader:
            inputs, targets = batch
            inputs, targets = inputs.to(device), targets.to(device)

            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, targets)
            loss.backward()
            optimizer.step()

            training_loss += loss.item()

        experiment_data["output_layer_variation"]["synthetic_cosmology"]["losses"][
            "train"
        ].append(training_loss / len(train_loader))

        model.eval()
        val_loss = 0.0
        with torch.no_grad():
            for batch in val_loader:
                inputs, targets = batch
                inputs, targets = inputs.to(device), targets.to(device)
                outputs = model(inputs)
                loss = criterion(outputs, targets)
                val_loss += loss.item()

                experiment_data["output_layer_variation"]["synthetic_cosmology"][
                    "predictions"
                ].extend(outputs.cpu().numpy())
                experiment_data["output_layer_variation"]["synthetic_cosmology"][
                    "ground_truth"
                ].extend(targets.cpu().numpy())

        val_loss /= len(val_loader)
        experiment_data["output_layer_variation"]["synthetic_cosmology"]["losses"][
            "val"
        ].append(val_loss)

        BER = np.exp(-val_loss)
        experiment_data["output_layer_variation"]["synthetic_cosmology"]["metrics"][
            "val"
        ].append(BER)

        print(
            f"Epoch {epoch + 1}: Variation = {variation}, Validation Loss = {val_loss:.4f}, BER = {BER:.4f}"
        )

    experiment_data["output_layer_variation"]["synthetic_cosmology"][
        "variation_types"
    ].append(variation)

np.save(os.path.join(working_dir, "experiment_data.npy"), experiment_data)
